        { q: "Click-Through Rate (CTR) in digital advertising measures:", options: ["How many people saw the ad", "The ratio of users who click on an ad to the number of total users who viewed it", "How much the ad cost", "How long the user stayed on the website"], a: 1 },
        { q: "Programmatic advertising uses:", options: ["Manual negotiations with publishers", "Automated technology and algorithms to buy and place digital ads in real-time", "Only billboards", "Only celebrity endorsements"], a: 1 }
